const LANG_STORAGE_KEY = "automatixfcz-lang";

function applyLanguage(lang) {
  const dict = translations[lang] || translations.nl;
  document.querySelectorAll("[data-i18n]").forEach((el) => {
    const key = el.getAttribute("data-i18n");
    if (dict[key]) el.textContent = dict[key];
  });
  document.querySelectorAll("[data-i18n-placeholder]").forEach((el) => {
    const key = el.getAttribute("data-i18n-placeholder");
    if (dict[key]) el.setAttribute("placeholder", dict[key]);
  });
  document.documentElement.setAttribute("lang", lang);
  const select = document.getElementById("langSelect");
  if (select) select.value = lang;
  localStorage.setItem(LANG_STORAGE_KEY, lang);
}

document.addEventListener("DOMContentLoaded", () => {
  const saved = localStorage.getItem(LANG_STORAGE_KEY);
  applyLanguage(saved && translations[saved] ? saved : "nl");
  document.getElementById("langSelect").addEventListener("change", (e) => applyLanguage(e.target.value));
});
